const raw = $input.first().json;
const { day, leads, config } = raw.body ?? raw;
const freq = config.reminders.frequencyDays;
const maxR = config.reminders.maxReminders;
let idCounter = Date.now();
function uid() { return 'a' + idCounter++; }
function ts() { return new Date().toISOString(); }

// --- Scoring ---
function budgetScore(b) { return b > 2000 ? 10 : b >= 500 ? 6 : 3; }
function intentScore(s) { return s === 'high' ? 9 : s === 'medium' ? 6 : 3; }
function timelineScore(d) { return d <= 7 ? 10 : d <= 21 ? 6 : 3; }
function computeScore(lead) {
  const bs = budgetScore(lead.formInputs.budget);
  const is = intentScore(lead.intentSignal);
  const tss = timelineScore(lead.formInputs.timelineDays);
  const { budgetWeight, intentWeight, timelineWeight } = config.scoring;
  const score = Math.round((bs * budgetWeight + is * intentWeight + tss * timelineWeight) / 100);
  const classification = score >= 7 ? 'Hot' : score >= 4 ? 'Warm' : 'Cold';
  return { score, classification, rationale: 'Budget ' + bs + '/10, Intent ' + is + '/10, Timeline ' + tss + '/10' };
}

// --- Seeded randomness ---
function seeded(leadId, salt) {
  const str = leadId + salt;
  let hash = 0;
  for (const c of str) hash = ((hash << 5) - hash) + c.charCodeAt(0);
  return (Math.abs(hash) % 10000) / 10000;
}
function pick(arr, leadId, salt) {
  return arr[Math.floor(seeded(leadId, salt) * arr.length)];
}

// --- Project description fallback ---
const DESC_FALLBACKS = [
  'Streamlining internal approval workflows for mid-market finance teams.',
  'An AI-powered support ticket triage system that routes issues to the right team.',
  'Automating lead qualification and follow-up for a B2B outbound sales motion.',
  'A document intelligence layer for contract review and compliance flagging.',
  'Real-time inventory sync and demand forecasting for e-commerce operators.',
  'Employee onboarding automation connecting HRMS, IT provisioning, and L&D.',
  'API-first payment orchestration handling retries and reconciliation.',
  'Compliance monitoring and reporting for regulated financial services firms.',
];
function resolveDesc(lead) {
  return (lead.projectDescription && lead.projectDescription.trim()) || pick(DESC_FALLBACKS, lead.id, 'projdesc');
}

// --- Humanised content ---
const POS_REPLIES = [
  (n, rep, proj) => 'Hi ' + rep.split(' ')[0] + ', thanks for reaching out. We've been evaluating options for ' + proj + ' and your approach looks promising. What's the typical onboarding timeline, and do you support custom integrations?

— ' + n,
  (n, rep, proj) => 'Hey ' + rep.split(' ')[0] + ' — good timing. We're mid-sprint on ' + proj + ' and this could be exactly what we need. Can you send over case studies from similar use cases? I'd like to share with my team before we book anything.

— ' + n,
  (n, rep, proj) => 'Hi ' + rep.split(' ')[0] + ', ' + n.split(' ')[0] + ' here. We've looked at a few vendors for ' + proj + ' and the gap has always been around flexibility and speed of setup. Can we do a quick 20-min intro call this week?

— ' + n,
  (n, rep, proj) => 'Hi! ' + proj + ' is on our roadmap this quarter. Your email caught my eye — especially the AI angle. Can you share technical docs? Our CTO will want to see the architecture.

— ' + n,
  (n, rep, proj) => 'Hey — sorry for the slow reply. ' + proj + ' is a priority but we've been burned by vendors who overpromised. What does a pilot look like and how quickly can we see results?

— ' + n,
];
const NEG_REPLIES = [
  (n) => 'Hi, thanks for the email. We're heads-down on a product launch this quarter and can't take on vendor evaluations right now. Follow up in 3 months.

— ' + n,
  (n) => 'Appreciate the outreach. We went with another provider last month. Not looking to switch right now.

— ' + n,
  (n) => 'Thanks for reaching out. We've decided to build this in-house for now. Will be in touch if that changes.

— ' + n,
];
const STAFF_FOLLOWUPS = [
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Thanks so much for getting back to us! To answer your questions on ' + proj + ': most teams are fully onboarded within 10–14 days. Our implementation team handles the heavy lifting.

I'd love to show you a quick demo tailored to your use case. I have slots open tomorrow — does morning or afternoon work?

' + rep,
  (n, rep, proj) => 'Hey ' + n.split(' ')[0] + ',

Great to hear from you! I pulled together case studies from teams who've tackled similar challenges in ' + proj + '. We typically see a 60–70% reduction in manual follow-up time within the first month.

Got 20 minutes this week for a live walkthrough?

' + rep,
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Thank you for the kind response! Based on what you've shared about ' + proj + ', I think there's a strong fit. I've also looped in our solutions engineer if you want to get your CTO involved early.

Calendar link below.

' + rep,
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Really glad this landed at the right time for ' + proj + '. The biggest wins typically come in the first 3 weeks once automation is live.

Can we do a 30-min discovery call? I'll come prepared.

' + rep,
];
const NUDGE_DRAFTS = [
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Apologies for the delay — things got hectic on our end. ' + proj + ' is exactly the kind of challenge we're built for and I don't want us to lose momentum. Would you still be open to a quick call?

' + rep,
  (n, rep, proj) => 'Hey ' + n.split(' ')[0] + ',

Sorry for going quiet after your reply — that's on me. Your note on ' + proj + ' stood out and I think there's a real fit. Would a 15-minute call work this week?

' + rep,
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Circling back to make sure your query on ' + proj + ' didn't fall through the cracks. Happy to answer questions over email too if a call isn't convenient.

' + rep,
];
const FU1 = [
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Just checking in — wanted to make sure my earlier note didn't get buried. We've been working with teams on ' + proj + ' challenges very similar to yours.

Would a quick 15-minute call make sense this week?

' + rep + '
via CloseIt AI',
  (n, rep, proj) => 'Hey ' + n.split(' ')[0] + ',

Following up on my note from a few days back. If ' + proj + ' is still on the radar, I'd love to reconnect.

' + rep + '
via CloseIt AI',
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

Hoping this finds you well. Following up on ' + proj + ' — we've had a few teams in similar situations recently. Happy to share specifics.

' + rep + '
via CloseIt AI',
];
const FU2 = [
  (n, rep, proj) => 'Hi ' + n.split(' ')[0] + ',

This will be my last note for now. If the timing for ' + proj + ' changes, just reply here and we'll pick up right where we left off.

' + rep + '
via CloseIt AI',
  (n, rep, proj) => 'Hey ' + n.split(' ')[0] + ',

Leaving the ball in your court from here. If ' + proj + ' becomes a priority, I'm easy to reach.

' + rep + '
via CloseIt AI',
];

function generateMoM(lead, rep, day) {
  const proj = lead.projectName;
  const desc = resolveDesc(lead);
  const first = lead.name.split(' ')[0];
  const repFirst = rep.split(' ')[0];
  const pains = ['manual handoffs between teams causing delays and lost context','lack of pipeline visibility until it was too late to act','inconsistent follow-up leading to leads going cold','too much time spent on tasks that should be automated'];
  const features = ['the AI-powered lead scoring and automated nudge system','the context-aware follow-up agent that knows when to escalate vs. wait','the real-time activity feed and CRM audit trail','the ability to configure cadence and scoring weights without touching code'];
  const pain = pick(pains, lead.id, 'pain');
  const feature = pick(features, lead.id, 'feature');
  return 'DISCOVERY CALL — MINUTES OF MEETING

Date: Day ' + day + '  |  Duration: 30 minutes
Attendees: ' + lead.name + ' (' + (lead.company || 'Prospect') + '), ' + rep + ' (CloseIt)

─────────────────────────────────────────

PROJECT CONTEXT
' + proj + ': ' + desc + '

─────────────────────────────────────────

DISCUSSION SUMMARY

1. Current State
   ' + first + ' walked through their existing workflow for ' + proj + '. Primary pain point: ' + pain + '.

2. Product Walkthrough
   ' + repFirst + ' demonstrated the AI automation suite. ' + first + ' flagged ' + feature + ' as particularly relevant.

3. Technical Fit
   Integration path mapped. Estimated setup: 10–14 days.

4. Commercial Alignment
   Budget: $' + lead.formInputs.budget + '. Timeline: ' + lead.formInputs.timelineDays + ' days.

─────────────────────────────────────────

AGREED NEXT STEPS

  ☐  ' + rep + ': Send formal proposal by Day ' + (day + 1) + '
  ☐  ' + first + ': Share workflow documentation
  ☐  ' + rep + ': Schedule technical review call for Day ' + (day + 3) + '

─────────────────────────────────────────

OUTCOME
Strong alignment. Decision expected by Day ' + (day + 5) + '. Sentiment: Positive ✓';
}

// --- Story arc ---
function getStory(lead) {
  const willReply = seeded(lead.id, 'willreply') < 0.6;
  const replyIsPositive = willReply && seeded(lead.id, 'positive') < 0.7;
  const staffDropsBall = replyIsPositive && seeded(lead.id, 'staffdrop') < 0.4;
  const replyDay = 2 + Math.floor(seeded(lead.id, 'replyDay') * 3);
  const staffActionDay = replyDay + 1;
  const hasMeeting = replyIsPositive && !staffDropsBall && seeded(lead.id, 'meeting') < 0.6;
  const meetingDay = hasMeeting ? staffActionDay + 1 + Math.floor(seeded(lead.id, 'meetingday') * 2) : null;
  const closeDay = meetingDay ? meetingDay + 2 : null;
  return { willReply, replyIsPositive, staffDropsBall, replyDay, staffActionDay, meetingDay, closeDay };
}

// --- Main loop ---
const allActions = [];
const leadUpdates = {};

for (const lead of leads) {
  const rel = day - lead.registeredOnDay;
  const actions = [];
  const updates = {};
  const story = getStory(lead);
  const rep = lead.assignedRep;
  const n = lead.name;
  const first = n.split(' ')[0];
  const proj = lead.projectName;

  // Day +1: Onboarding
  if (rel === 1) {
    const { score, classification, rationale } = computeScore(lead);
    updates.score = score; updates.classification = classification;
    updates.status = 'Contacted'; updates.lastActionDay = day; updates.nextReminderDay = day + freq;
    const desc = resolveDesc(lead);
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: n, actor: 'system', summary: 'Onboarding email sent to ' + n, detail: { channel: 'Email', from: rep, to: lead.email, subject: proj + ' — let's talk', body: 'Hi ' + first + ',

Thanks for reaching out. We saw you're working on ' + proj + ' — ' + desc.split('.')[0].toLowerCase() + '.

We help teams like yours automate the repetitive parts. I'd love to understand your workflow and show you what that could look like.

Would a 20-minute call this week work?

' + rep }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'score_update', leadId: lead.id, leadName: n, actor: 'ai', summary: 'AI scored ' + n + ' — ' + score + '/10 (' + classification + ')', detail: { score, classification, rationale, weights: config.scoring }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'rep_assigned', leadId: lead.id, leadName: n, actor: 'system', summary: rep + ' assigned to manage ' + n, detail: { rep, note: classification + ' lead (' + score + '/10). Project: ' + proj }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'proposal_sent', leadId: lead.id, leadName: n, actor: 'team', summary: rep + ' sent capability overview to ' + n, detail: { rep, subject: 'Quick overview — ' + proj, body: 'Hi ' + first + ',

Following up with a quick overview for ' + proj + ':

• Automated lead capture and AI scoring
• Contextual follow-up sequences
• CRM-layer agent that tells your team who to contact and when
• Full audit trail with zero manual data entry

Budget: $' + lead.formInputs.budget + ' | Timeline: ' + lead.formInputs.timelineDays + ' days — both look very achievable.

' + rep }, timestamp: ts() });
  }

  // Lead replies
  const alreadyEngaged = ['Replied','Meeting Scheduled','Closed Won','Closed Lost','Nurture'].includes(lead.status);
  if (story.willReply && rel === story.replyDay && !alreadyEngaged) {
    if (story.replyIsPositive) {
      const msgFn = pick(POS_REPLIES, lead.id, 'posreply');
      actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: n, actor: 'customer', summary: n + ' replied — interested in ' + proj, detail: { from: lead.email, to: rep, body: msgFn(n, rep, proj) }, timestamp: ts() });
      updates.status = 'Replied'; updates.nextReminderDay = null; updates.lastActionDay = day;
    } else {
      const msgFn = pick(NEG_REPLIES, lead.id, 'negreply');
      actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: n, actor: 'customer', summary: n + ' replied — not the right time', detail: { from: lead.email, to: rep, body: msgFn(n) }, timestamp: ts() });
      actions.push({ id: uid(), day, type: 'moved_to_nurture', leadId: lead.id, leadName: n, actor: 'system', summary: n + ' moved to Nurture after negative reply', detail: { reason: 'Lead replied with a deferral. Sequence paused.' }, timestamp: ts() });
      updates.status = 'Nurture'; updates.nextReminderDay = null; updates.lastActionDay = day;
    }
  }

  // Staff action day
  if (story.replyIsPositive && rel === story.staffActionDay && lead.status === 'Replied') {
    if (story.staffDropsBall) {
      const draftFn = pick(NUDGE_DRAFTS, lead.id, 'nudgedraft');
      actions.push({ id: uid(), day, type: 'staff_nudge', leadId: lead.id, leadName: n, actor: 'system', summary: '⚡ Nudge sent to ' + rep + ' — ' + n + ' replied ' + (day - (lead.registeredOnDay + story.replyDay)) + ' day(s) ago, no action logged', detail: { to: rep, reason: n + ' sent a positive reply on Day ' + (lead.registeredOnDay + story.replyDay) + ' but no follow-up has been logged by ' + rep + '.', draftSubject: 'Re: ' + proj + ' — following up on ' + first + ''s reply', draftBody: draftFn(n, rep, proj) }, timestamp: ts() });
      updates.status = 'Awaiting Reply'; updates.nextReminderDay = day + freq; updates.lastActionDay = day;
    } else {
      const msgFn = pick(STAFF_FOLLOWUPS, lead.id, 'staffreply');
      actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: n, actor: 'team', summary: rep + ' followed up with ' + n, detail: { from: rep, to: lead.email, subject: 'Re: ' + proj + ' — great to hear from you', body: msgFn(n, rep, proj) }, timestamp: ts() });
      updates.status = 'Awaiting Reply'; updates.nextReminderDay = day + freq; updates.lastActionDay = day;
    }
  }

  // Meeting
  const closedStatuses = ['Closed Won','Closed Lost','Nurture'];
  if (story.meetingDay && rel === story.meetingDay && !closedStatuses.includes(lead.status)) {
    actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: n, actor: 'customer', summary: n + ' confirmed the discovery call', detail: { from: lead.email, to: rep, body: 'Hi ' + rep.split(' ')[0] + ', yes — let's do it. Looking forward to the demo.

— ' + first }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'meeting_scheduled', leadId: lead.id, leadName: n, actor: 'system', summary: 'Discovery call booked — ' + n + ' × ' + rep, detail: { date: 'Day ' + day, duration: '30 min', rep, lead: n, project: proj }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'meeting_minutes', leadId: lead.id, leadName: n, actor: 'team', summary: 'MoM logged — ' + n + ' discovery call', detail: { mom: generateMoM(lead, rep, day) }, timestamp: ts() });
    updates.status = 'Meeting Scheduled'; updates.nextReminderDay = null; updates.lastActionDay = day;
  }

  // Close
  if (story.closeDay && rel === story.closeDay && !closedStatuses.includes(lead.status)) {
    actions.push({ id: uid(), day, type: 'closed_won', leadId: lead.id, leadName: n, actor: 'team', summary: '🎉 ' + n + ' closed won — ' + proj, detail: { rep, value: '$' + lead.formInputs.budget, note: 'Proposal accepted. Agreement signed. Onboarding starts next week.' }, timestamp: ts() });
    updates.status = 'Closed Won'; updates.nextReminderDay = null; updates.lastActionDay = day;
  }

  // Automated follow-ups
  const engagedStatuses = ['Replied','Meeting Scheduled','Closed Won','Closed Lost','Nurture'];
  const onSpecialDay = rel === story.replyDay || rel === story.staffActionDay || rel === story.meetingDay || rel === story.closeDay;
  if (!engagedStatuses.includes(lead.status) && !onSpecialDay && lead.nextReminderDay === day && lead.remindersSent < maxR) {
    const rn = lead.remindersSent + 1;
    const msgFn = rn === 1 ? pick(FU1, lead.id, 'fu1') : pick(FU2, lead.id, 'fu2');
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: n, actor: 'ai', summary: 'Follow-up #' + rn + ' sent to ' + n + ' (AI-drafted)', detail: { from: rep + ' via CloseIt AI', to: lead.email, subject: rn === 1 ? 'Checking in — ' + proj : 'Last note from us — ' + first, body: msgFn(n, rep, proj) }, timestamp: ts() });
    updates.remindersSent = rn; updates.lastActionDay = day;
    if (rn >= maxR) {
      updates.status = 'Nurture'; updates.nextReminderDay = null;
      actions.push({ id: uid(), day, type: 'moved_to_nurture', leadId: lead.id, leadName: n, actor: 'system', summary: n + ' moved to Nurture — max follow-ups reached', detail: { reason: maxR + ' follow-ups sent with no response. Sequence paused.' }, timestamp: ts() });
    } else {
      updates.nextReminderDay = day + freq; updates.status = 'Awaiting Reply';
    }
  }

  allActions.push(...actions);
  if (Object.keys(updates).length > 0) leadUpdates[lead.id] = updates;
}

return [{ json: { day, actions: allActions, leadUpdates } }];

// Split the actions array into individual items for Sheets append
const { day, actions, leadUpdates } = $input.first().json;

if (!actions || actions.length === 0) {
  // No actions — return a dummy item to keep the flow going
  return [{ json: { _noActions: true, day, leadUpdates } }];
}

return actions.map(action => ({
  json: {
    lead_id: action.leadId,
    day: action.day,
    action_type: action.type,
    actor: action.actor,
    summary: action.summary,
    detail_json: JSON.stringify(action.detail || {}),
    timestamp: action.timestamp
  }
}));
